#include <stdio.h>
#define MOD 1000000007LL

long long modPow(long long base, long long exp) {
    long long res = 1 % MOD;
    base %= MOD;
    while (exp > 0) {
        if (exp & 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const long long inv25 = modPow(25, MOD - 2);
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long k = N / 2; // floor(N/2)
        long long pow26k = modPow(26, k);
        long long sum = (26LL * ((pow26k - 1 + MOD) % MOD)) % MOD;
        sum = (sum * inv25) % MOD; // sum = 26^1 + ... + 26^k
        long long ans;
        if (N % 2 == 0) {
            ans = (2LL * sum) % MOD;
        } else {
            long long pow26kp1 = (pow26k * 26) % MOD; // 26^{k+1}
            ans = ( (2LL * sum) % MOD + pow26kp1 ) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

