#include <bits/stdc++.h>
using namespace std;
const long long MOD = 1000000007LL;

long long modPow(long long base, long long exp) {
    long long res = 1 % MOD;
    base %= MOD;
    while (exp) {
        if (exp & 1) res = res * base % MOD;
        base = base * base % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    const long long inv25 = modPow(25, MOD - 2);
    while (T--) {
        long long N; cin >> N;
        long long k = N / 2;
        long long pow26k = modPow(26, k);
        long long sum = 26LL * ((pow26k - 1 + MOD) % MOD) % MOD;
        sum = sum * inv25 % MOD; // geometric sum
        long long ans;
        if (N % 2 == 0) {
            ans = (2LL * sum) % MOD;
        } else {
            long long pow26kp1 = pow26k * 26 % MOD;
            ans = (2LL * sum + pow26kp1) % MOD;
        }
        cout << ans << '\n';
    }
    return 0;
}

