import java.io.*;
import java.util.*;

public class Main {
    static final long MOD = 1_000_000_007L;
    static long modPow(long base, long exp) {
        long res = 1L;
        base %= MOD;
        while (exp > 0) {
            if ((exp & 1L) == 1L) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp >>= 1;
        }
        return res;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        long inv25 = modPow(25, MOD - 2);
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            long N = Long.parseLong(br.readLine().trim());
            long k = N / 2;
            long pow26k = modPow(26, k);
            long sum = 26L * ((pow26k - 1 + MOD) % MOD) % MOD;
            sum = sum * inv25 % MOD; // sum of 26^i for i=1..k
            long ans;
            if (N % 2 == 0) {
                ans = (2L * sum) % MOD;
            } else {
                long pow26kp1 = pow26k * 26L % MOD;
                ans = (2L * sum + pow26kp1) % MOD;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

