const fs = require('fs');
const MOD = 1000000007n;
function modPow(base, exp) {
  base %= MOD;
  let result = 1n;
  while (exp > 0n) {
    if (exp & 1n) result = (result * base) % MOD;
    base = (base * base) % MOD;
    exp >>= 1n;
  }
  return result;
}
const inv25 = modPow(25n, MOD - 2n);
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = BigInt(input[idx++]);
  const k = N / 2n; // floor
  const pow26k = modPow(26n, k);
  let sum = 26n * ((pow26k - 1n + MOD) % MOD) % MOD;
  sum = sum * inv25 % MOD; // geometric sum
  let ans;
  if (N % 2n === 0n) {
    ans = (2n * sum) % MOD;
  } else {
    const pow26kp1 = (pow26k * 26n) % MOD;
    ans = (2n * sum + pow26kp1) % MOD;
  }
  outputs.push(ans.toString());
}
